import { fp, ft, fd } from './format.js';

export function printTicket(order) {
  const w = window.open('', '_blank', 'width=340,height=700');
  if (!w) return;
  const items = order.items.map(item => {
    let c = '';
    if (item.cust) {
      const x = item.cust;
      if (x.retraits?.length) c += x.retraits.map(r => `<div class="c r">— ${r}</div>`).join('');
      if (x.supplements?.length) c += x.supplements.map(s => `<div class="c s">+ ${s}</div>`).join('');
      if (x.sauces?.length) c += x.sauces.map(s => `<div class="c a">Sauce : ${s}</div>`).join('');
      if (x.sauce) c += `<div class="c a">Sauce : ${x.sauce}</div>`;
      if (x.version) c += `<div class="c v">${x.version}</div>`;
      if (x.type) c += `<div class="c v">Type : ${x.type}</div>`;
      if (x.choix) c += `<div class="c v">Choix : ${x.choix}</div>`;
      if (x.toppings?.length) c += x.toppings.map(t => `<div class="c s">+ ${t}</div>`).join('');
      if (x.glace) c += `<div class="c s">+ Supplement Glace</div>`;
      if (x.drink) c += `<div class="c a">Boisson : ${x.drink}</div>`;
      if (x.burgers) c += x.burgers.map((b, i) => `<div class="c v">${i + 1}. ${b.name}</div>`).join('');
      if (x.note) c += `<div class="c n">${x.note}</div>`;
    }
    return `<div class="item"><div class="row"><span class="q">${item.qty}x</span><span class="n">${item.name}</span><span class="p">${fp(item.total)}</span></div>${c}</div>`;
  }).join('');
  w.document.write(`<!DOCTYPE html><html><head><meta charset="utf-8"><title>#${order.num}</title>
<style>*{margin:0;padding:0;box-sizing:border-box;}body{font-family:'Courier New',monospace;width:80mm;padding:6mm 4mm 20mm;font-size:13px;}
.hd{text-align:center;padding-bottom:8px;margin-bottom:8px;border-bottom:2px dashed #000;}
.logo{font-size:26px;font-weight:900;letter-spacing:3px;}.sub{font-size:11px;letter-spacing:1px;margin:2px 0 6px;}
.num{font-size:44px;font-weight:900;margin:6px 0;}.client{font-size:22px;font-weight:900;margin:4px 0;letter-spacing:2px;border-top:1px dashed #ccc;border-bottom:1px dashed #ccc;padding:5px 0;}.dt{font-size:12px;}
.item{padding:5px 0;border-bottom:1px dashed #ccc;}.row{display:flex;align-items:baseline;gap:4px;}
.q{font-size:15px;font-weight:900;min-width:28px;}.n{flex:1;font-size:13px;font-weight:700;text-transform:uppercase;}.p{font-size:13px;font-weight:700;}
.c{padding-left:32px;font-size:11px;margin-top:2px;}.r{font-weight:700;}.s{font-weight:700;}
.snack{font-size:11px;line-height:1.5;margin:4px 0 6px;color:#333;}
.svc{font-size:14px;font-weight:700;margin:3px 0;letter-spacing:1px;text-transform:uppercase;}
.paid{margin-top:4px;text-align:right;font-size:13px;font-weight:700;}
.tot{margin-top:8px;text-align:right;border-top:2px dashed #000;padding-top:8px;}.tot-val{font-size:24px;font-weight:900;}
.logo-img{display:block;margin:0 auto 2px;width:140px;height:auto;}.receipt-caisse{min-height:14cm;}.ft{text-align:center;margin-top:16px;padding-top:8px;border-top:1px dashed #000;font-size:11px;line-height:1.8;}
@media print{body{width:80mm;}@page{margin:0;size:80mm auto;}}</style>
</head><body class="receipt-caisse">
<img class="logo-img" src="data:image/png;base64,"/>
<div class="hd"><div class="logo">O'SMASH</div><div class="sub" style="font-size:10px;line-height:1.4;">Vous serez toujours les bienvenus chez OSMASH</div>
<div class="snack">07 56 88 73 47<br>14 Rue Victor Hugo, 54400 Longwy</div>
<div class="num">#${order.num}</div>${order.client ? `<div class="client">${order.client.toUpperCase()}</div>` : ''}
${order.service ? `<div class="svc">${order.service}</div>` : ''}
<div class="dt">${fd(order.date)} · ${ft(order.date)}</div></div>
${items}
<div class="tot"><div style="font-size:13px;">TOTAL</div><div class="tot-val">${fp(order.total)}</div></div>
${order.payment ? `<div class="paid">Paiement : ${order.payment.toUpperCase()}</div>` : ''}
<div class="ft">Merci de votre visite !<br>Bon appétit !</div>
<script>window.onload=()=>{window.print();setTimeout(()=>window.close(),2000)}<\/script>
</body></html>`);
  w.document.close();
}
